import { useState, useCallback, useEffect } from 'react';
import { optimise } from './engineV2';
import { I18N } from './i18n';
import { supabase, saveProject, loadProject, signOut } from './supabase';
import ProjectForm from './components/ProjectForm';
import PiecesList from './components/PiecesList';
import Results from './components/Results';
import AuthScreen from './components/AuthScreen';
import ProjectsScreen from './components/ProjectsScreen';
import { Scissors, ChevronLeft, User, LogOut, Save, Database, Globe, Disc } from 'lucide-react';
import './App.css';

const SCREENS = { AUTH: 'auth', PROJECTS: 'projects', FORM: 'form', PIECES: 'pieces', RESULTS: 'results' };
const DEFAULT_PROJECT = { name: '', client: '', company: '', panel: { w: 244, h: 122 }, kerf: 3, tolerance: 10, pricePerPanel: 39.8, pieces: [], furniture: [], devisNum: '', supabaseId: null };

// --- COMPOSANT HEADER INTERNE (Simple et robuste) ---
const SimpleHeader = ({ title, subtitle, onBack, user, onLogout, steps, onSave, saving, saveMsg, lang, onToggleLang }) => {
  return (
    <div className="sticky top-0 z-50 bg-[#0a0a0a] border-b border-white/10 shadow-lg h-16 flex items-center justify-between px-4 max-w-5xl mx-auto w-full">
      {/* Gauche */}
      <div className="flex items-center gap-3">
        {onBack && (
          <button onClick={onBack} className="p-2 text-slate-400 hover:text-white"><ChevronLeft size={20}/></button>
        )}
        <div>
          <h1 className="text-white font-bold text-sm">{title}</h1>
          {subtitle && <p className="text-[10px] text-slate-500">{subtitle}</p>}
        </div>
      </div>

      {/* Centre (Steps) */}
      {steps && steps.length > 0 && (
        <div className="hidden md:flex items-center gap-2 bg-[#111] px-3 py-1 rounded-full border border-white/5">
          {steps.map((s, i) => (
            <div key={i} className={`text-[10px] font-bold uppercase ${s.active ? 'text-orange-500' : 'text-slate-600'}`}>
              {i+1}. {s.label} {i < steps.length-1 && '|'}
            </div>
          ))}
        </div>
      )}

      {/* Droite */}
      <div className="flex items-center gap-2">
        {onSave && !saving && (
          <button onClick={onSave} className="p-2 text-slate-400 hover:text-green-400" title="Sauvegarder"><Disc size={18}/></button>
        )}
        <button onClick={onToggleLang} className="p-2 text-slate-400 hover:text-white font-bold text-xs border border-white/10 rounded">
          {lang === 'fr' ? 'EN' : 'FR'}
        </button>
        {user && (
          <button onClick={onLogout} className="p-2 text-slate-400 hover:text-red-400"><LogOut size={18}/></button>
        )}
      </div>
    </div>
  );
};

export default function App() {
  // GESTION LANGUE SIMPLE
  const [lang, setLang] = useState('fr');
  const tr = I18N[lang] || I18N['fr'];

  const [screen, setScreen] = useState(SCREENS.AUTH);
  const [user, setUser] = useState(null);
  const [project, setProject] = useState({ ...DEFAULT_PROJECT });
  const [results, setResults] = useState(null);
  const [computing, setComputing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState('');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) { setUser(session.user); setScreen(SCREENS.PROJECTS); }
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_e, s) => {
      if (s?.user) { setUser(s.user); setScreen(SCREENS.PROJECTS); }
      else { setUser(null); setScreen(SCREENS.AUTH); }
    });
    return () => subscription.unsubscribe();
  }, []);

  const startNew = () => { setProject({...DEFAULT_PROJECT}); setResults(null); setScreen(SCREENS.FORM); };
  const goBack = () => {
    if(screen===SCREENS.RESULTS) setScreen(SCREENS.PIECES);
    else if(screen===SCREENS.PIECES) setScreen(SCREENS.FORM);
    else if(screen===SCREENS.FORM) setScreen(user?SCREENS.PROJECTS:SCREENS.AUTH);
  };

  const handleLoad = async (id) => {
    const { data } = await loadProject(id);
    if(!data) return;
    setProject({...data.project_data, supabaseId: data.id});
    setScreen(data.results_data ? SCREENS.RESULTS : SCREENS.PIECES);
    if(data.results_data) setResults(data.results_data);
  };

  const handleOptimize = useCallback(() => {
    setComputing(true);
    setTimeout(async () => {
      const res = optimise(project.pieces, project.panel, {kerf: project.kerf, tolerance: project.tolerance});
      setResults(res); setComputing(false); setScreen(SCREENS.RESULTS);
      if(user) {
        setSaving(true);
        await saveProject(project, res);
        setSaving(false); setSaveMsg('OK'); setTimeout(()=>setSaveMsg(''),2000);
      }
    }, 50);
  }, [project, user]);

  const handleSave = async () => {
    if(!user) return;
    setSaving(true);
    await saveProject(project, results);
    setSaving(false); setSaveMsg('OK'); setTimeout(()=>setSaveMsg(''),2000);
  };

  const toggleLang = () => setLang(l => l==='fr'?'en':'fr');

  // Configuration du Header
  let hTitle = "", hSub = "", steps = [];
  if(screen===SCREENS.FORM) { hTitle=tr.newProject; steps=[{label:tr.panel,active:true},{label:tr.pieces,active:false},{label:tr.results,active:false}]; }
  if(screen===SCREENS.PIECES) { hTitle=project.name||tr.newProject; steps=[{label:tr.panel,active:true},{label:tr.pieces,active:true},{label:tr.results,active:false}]; }
  if(screen===SCREENS.RESULTS) { hTitle=tr.results; steps=[{label:tr.panel,active:true},{label:tr.pieces,active:true},{label:tr.results,active:true}]; }

  const hasHeader = screen !== SCREENS.AUTH;

  return (
    <div className="min-h-screen bg-[#050505] text-slate-200 font-sans">

      {/* HEADER CONDITIONNEL */}
      {hasHeader && (
        <SimpleHeader 
          title={hTitle} subtitle={hSub} steps={steps}
          onBack={goBack} user={user} onLogout={()=>{signOut();setUser(null);setScreen(SCREENS.AUTH);}}
          onSave={handleSave} saving={saving} saveMsg={saveMsg}
          lang={lang} onToggleLang={toggleLang}
        />
      )}

      {/* CONTENU PRINCIPAL - KEY MAGIC POUR LA LANGUE */}
      <main className={`max-w-5xl mx-auto px-4 ${hasHeader ? 'mt-20' : 'mt-0'} mb-20`}>

        {screen === SCREENS.AUTH && <AuthScreen key={lang} onSkip={()=>setScreen(SCREENS.PROJECTS)} />}

        {screen === SCREENS.PROJECTS && (
          <ProjectsScreen key={lang} user={user} onNew={startNew} onLoad={handleLoad} />
        )}

        {screen === SCREENS.FORM && (
          <ProjectForm key={lang} t={tr} project={project} onChange={setProject} onNext={()=>setScreen(SCREENS.PIECES)} />
        )}

        {screen === SCREENS.PIECES && (
          <PiecesList key={lang} t={tr} project={project} onChange={setProject} onOptimize={handleOptimize} computing={computing} />
        )}

        {screen === SCREENS.RESULTS && results && (
          <Results key={lang} t={tr} results={results} project={project} />
        )}

      </main>
    </div>
  );
}
